const fs=require('fs');const path=require('path');const flatted=require('flatted');function tryParse(filePath,defaultValue){let result;try{result=readJSON(filePath);}catch(ex){result=defaultValue;}
return result;}
function readJSON(filePath){return flatted.parse(fs.readFileSync(filePath,{encoding:'utf8',}));}
function writeJSON(filePath,data){fs.mkdirSync(path.dirname(filePath),{recursive:true,});fs.writeFileSync(filePath,flatted.stringify(data));}
module.exports={tryParse,readJSON,writeJSON};